include "/home/saint/bun/src/parsers/toml.dfy"

module TomlSemicolonAttempt {
  import opened Toml

  method TOML_SEMICOLON_COMMENT_AT_FILE_START_Witness()
  {
    // Zig edge case: file begins with semicolon. In Zig this is a comment
    // because has_newline_before is true at file start (end == 0).
    var src := new Source([59, 99, 111, 109, 109, 101, 110, 116, 10, 97]);
    // Existing Dafny model accepts an arbitrary pre-tokenized stream; there is
    // no invariant tying stream[0].loc/text to source.contents or comment skipping.
    var stream := [LexItem(t_identifier, [59], 0.0, 0, true)];
    var lexer := new Lexer(src, stream);

    // Desired Zig-derived fact would be that scanning did not produce a token
    // at the semicolon/comment start; it skipped to after the line break or EOF.
    assert lexer.start > 0;
  }

  method TOML_SEMICOLON_COMMENT_AFTER_NEWLINE_Witness()
  {
    var src := new Source([97, 10, 59, 99, 10, 98]);
    var stream := [LexItem(t_identifier, [59], 0.0, 2, true)];
    var lexer := new Lexer(src, stream);
    assert lexer.start > 2;
  }
}

